function resizeSlide(){var o=1280,p=720,e=window.innerWidth,i=window.innerHeight,n=Math.min(e/o,i/p);n>1&&(n=1);var c=(e-o*n)/2,a=(i-p*n)/2;$("#kad_container").css({transform:"scale("+n+")",left:c+"px",top:a+"px"}),$("#kad_container").addClass("visible")}var kad_cursor="modeB",kad_container_width=1024,kad_container_height=768,CLMPlayer=CLMPlayer||{};CLMPlayer.gotoSlide=function(o,p,e){window.location.href=p},$(".open-pop1").click(function(){$(".popup1").removeClass("popup-oculto")}),$(".open-pop2").click(function(){$(".popup2").removeClass("popup-oculto")}),$(".open-pop3").click(function(){$(".popup3").removeClass("popup-oculto")}),$(".popup .close-pop1, .popup .close-pop2, .popup .close-pop3").click(function(){$(".popup1, .popup2, .popup3").addClass("popup-oculto")}),$(".abrir-paso1").click(function(){$(".paso1").removeClass("ocultar")}),$(".abrir-paso2").click(function(){$(".paso2").removeClass("ocultar")}),$(".abrir-paso3").click(function(){$(".paso3").removeClass("ocultar")}),$(document).ready(function(){resizeSlide()}),$(window).on("resize",function(){resizeSlide()});